import React, { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import './ProductDetail.css';
import axios from 'axios';
import Footer from './Footer';
import { FaHeart } from "react-icons/fa";
import { addToCart, addToWishlist, removeFromWishlist } from "../services/api";

function ProductDetail() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [product, setProduct] = useState(null);
  const [selectedImg, setSelectedImg] = useState(0);
  const [selectedSize, setSelectedSize] = useState(null);
  const [pincode, setPincode] = useState('');
  const [pinMsg, setPinMsg] = useState('');
  const [related, setRelated] = useState([]);
  const [isWishlisted, setIsWishlisted] = useState(false);

  const token = localStorage.getItem('token');

  useEffect(() => {
    axios.get(`http://localhost:5000/api/products/${id}`)
      .then(res => {
        setProduct(res.data);
        setSelectedImg(0);
        setSelectedSize(null);

        const wishlist = JSON.parse(localStorage.getItem('wishlist') || '[]');
        const exists = wishlist.find(it => it._id === res.data._id);
        if (exists) setIsWishlisted(true);
      })
      .catch(err => console.error(err));
  }, [id]);

  useEffect(() => {
    axios.get(`http://localhost:5000/api/products/${id}/related`)
      .then(res => setRelated(res.data))
      .catch(err => console.error(err));
  }, [id]);

  const handleCheckPincode = () => {
    const valid = /^[1-9][0-9]{5}$/.test(pincode);
    if (!valid) return setPinMsg('❌ Invalid pincode. Enter 6 digits');
    const last = Number(pincode[pincode.length-1]);
    setPinMsg(last % 2 === 0 
      ? '✅ Delivery available: 3–5 days' 
      : '✅ Delivery available: 5–7 days'
    );
  };

  const handleWishlist = async () => {
    if (!token) return alert("❌ Please login first");

    try {
      if (isWishlisted) {
        await removeFromWishlist({ productId: product._id });
        setIsWishlisted(false);
      } else {
        await addToWishlist({ productId: product._id });
        setIsWishlisted(true);
      }
      window.dispatchEvent(new Event("wishlistUpdated"));
    } catch (err) {
      console.error(err);
      alert("❌ Could not update wishlist");
    }
  };

  const handleAddToCart = async () => {
    if (!token) return alert("❌ Please login first");

    if (product?.sizes?.length && !selectedSize) return alert("❌ Select size");

    try {
      await addToCart({
        productId: product._id,
        quantity: 1,
        size: selectedSize || "FREE",
      });
      navigate("/cart");
    } catch (err) {
      console.error(err);
      alert("❌ Could not add to cart");
    }
  };

  const handleBuyNow = () => {
    if (!token) return alert("❌ Please login first");
    if (product?.sizes?.length && !selectedSize) return alert("❌ Select size");
    navigate("/checkout");
  };

  if (!product) return <p>Loading...</p>;

  const gallery = product.images?.length ? product.images : [product.image];
  const mainImg = gallery[selectedImg] || product.image;

  return (
    <>
      <div className="product-detail-container">
        <div className="product-gallery">
          <div className="main-image"><img src={mainImg} alt={product.name} /></div>
          {gallery.length>1 && (
            <div className="thumbs">
              {gallery.map((src, idx) => (
                <button key={idx} className={`thumb ${idx===selectedImg?'active':''}`} onClick={()=>setSelectedImg(idx)}>
                  <img src={src} alt={`${product.name} ${idx+1}`} />
                </button>
              ))}
            </div>
          )}
        </div>

        <div className="product-info-section">
          <div className="top-row">
            <h2>{product.name}</h2>
            <button className={`heart-btn ${isWishlisted?'active':''}`} onClick={handleWishlist}>
              <FaHeart />
            </button>
          </div>
          <p className="price">₹{product.price}</p>

          {product.sizes?.length>0 ? (
            <div className="sizes-wrap">
              <p className="label">Select Size:</p>
              <div className="sizes">
                {product.sizes.map(s => (
                  <button key={s} className={`size-chip ${selectedSize===s?'selected':''}`} onClick={()=>setSelectedSize(s)}>{s}</button>
                ))}
              </div>
              <p className="size-info">Available: {product.sizes.join(", ")}</p>
            </div>
          ) : <p className="size">Size: Free Size</p>}

          <p className="description">{product.description||"No description available."}</p>

          <div className="pincode-checker">
            <input type="text" placeholder="Enter pincode" value={pincode} onChange={e=>setPincode(e.target.value)} maxLength={6} />
            <button onClick={handleCheckPincode}>Check</button>
          </div>
          {pinMsg && <p className="pin-msg">{pinMsg}</p>}

          <div className="product-buttons">
            <button onClick={handleAddToCart} className="add-to-cart-btn">Add to Cart</button>
            <button onClick={handleBuyNow} className="buy-now-btn">Buy Now</button>
          </div>
        </div>
      </div>

      {related.length>0 && (
        <div className="related-wrap">
          <h3>Related Products</h3>
          <div className="related-grid">
            {related.map(item => (
              <Link to={`/product/${item._id}`} key={item._id} className="rel-card">
                <div className="rel-img"><img src={item.images?.[0]||item.image} alt={item.name} /></div>
                <div className="rel-info">
                  <p className="rel-name">{item.name}</p>
                  <p className="rel-price">₹{item.price}</p>
                </div>
              </Link>
            ))}
          </div>
        </div>
      )}

      <Footer />
    </>
  );
}

export default ProductDetail;
